import 'package:flutter/material.dart';import 'package:firebase_auth/firebase_auth.dart';import 'package:cloud_firestore/cloud_firestore.dart';import 'package:intl/intl.dart';import 'package:url_launcher/url_launcher.dart';import 'package:flutter_local_notifications/flutter_local_notifications.dart';import 'package:timezone/timezone.dart' as tz;import 'package:timezone/data/latest.dart' as tz;import 'package:provider/provider.dart'; // 1. Thêm import Providerimport 'package:shared_preferences/shared_preferences.dart'; // Thêm SharedPreferences để lưu trạng tháiimport 'theme_provider.dart'; // 2. Thêm import ThemeProviderimport 'login.dart';import 'admin_page.dart'; // Import trang Admin mớiclass HomeScreen extends StatefulWidget {  const HomeScreen({super.key});  @override  State<HomeScreen> createState() => _HomeScreenState();}class _HomeScreenState extends State<HomeScreen> {  int _currentIndex = 0;  bool isVietnamese = true;  final ScrollController _scrollController = ScrollController();  final TextEditingController _searchController = TextEditingController();  final TextEditingController _chatController = TextEditingController();  final TextEditingController _nameController = TextEditingController();  final TextEditingController _currentPasswordController =      TextEditingController();  final TextEditingController _newPasswordController = TextEditingController();  final TextEditingController _confirmPasswordController =      TextEditingController();  final User? user = FirebaseAuth.instance.currentUser;  Color _avatarColor = Colors.blue;  bool _isTyping = false;  final FlutterLocalNotificationsPlugin flutterLocalNotificationsPlugin =      FlutterLocalNotificationsPlugin();  Map<String, dynamic> get lang => {    'home': isVietnamese ? "Trang chủ" : "Home",    'booking': isVietnamese ? "Lịch hẹn" : "Appointment",    'chat': isVietnamese ? "Tin nhắn" : "Message",    'profile': isVietnamese ? "Hồ sơ" : "Profile",    'welcome': isVietnamese ? "Chào bạn! 👋" : "Hello! 👋",    'find_doc': isVietnamese ? "Tìm bác sĩ của bạn" : "Find your doctor",    'search_hint': isVietnamese ? "Tìm bác sĩ..." : "Search doctor...",    'dept': isVietnamese ? "Chuyên khoa" : "Speciality",    'all': isVietnamese ? "Xem tất cả" : "See all",    'book_btn': isVietnamese ? "Bấm để đặt lịch" : "Book now",    'my_booking': isVietnamese ? "Lịch hẹn của bạn" : "Your Appointments",    'no_booking': isVietnamese        ? "Chưa có lịch hẹn nào."        : "No appointments yet.",    'patient': isVietnamese ? "Người khám" : "Patient",    'change_pw': isVietnamese ? "Đổi mật khẩu" : "Change Password",    'logout': isVietnamese ? "Đăng xuất" : "Logout",    'call_hotline': isVietnamese ? "Gọi Hotline" : "Call Hotline",    'chat_hint': isVietnamese ? "Nhập tin nhắn..." : "Type a message...",    'bot_typing': isVietnamese ? "Bác sĩ đang gõ..." : "Doctor is typing...",    'reset_chat': isVietnamese ? "Làm mới chat" : "Reset chat",    'select_hosp': isVietnamese ? "Chọn nơi khám bệnh" : "Select Hospital",    'hosp_title': isVietnamese ? "Danh sách bệnh viện" : "Hospital List",    'back_hosp': isVietnamese ? "Đổi bệnh viện" : "Change Hospital",    'hosp_desc': isVietnamese        ? "Vui lòng chọn bệnh viện để xem bác sĩ"        : "Choose a hospital to see doctors",  };  String? _selectedHospital;  String? _selectedDeptFilter; // Biến lọc chuyên khoa  List<Map<String, dynamic>> bookedAppointments = [];  List<Map<String, dynamic>> _messages = [];  @override  void initState() {    super.initState();    _resetChat();    _initNotifications(); // Khởi tạo và xin quyền thông báo    _loadAppState();    _fetchAppointments();  }  // --- HÀM TỰ ĐỘNG GÁN ICON THEO TÊN (DÙNG CHO TRANG CHỦ) ---  IconData _getIconForSpeciality(String name) {    name = name.toLowerCase();    if (name.contains("tim") || name.contains("mạch"))      return Icons.favorite_rounded;    if (name.contains("nhi") || name.contains("trẻ"))      return Icons.child_care_rounded;    if (name.contains("mắt")) return Icons.visibility_rounded;    if (name.contains("tâm thần") || name.contains("não"))      return Icons.psychology_rounded;    if (name.contains("chỉnh hình") || name.contains("xương"))      return Icons.healing_rounded;    if (name.contains("nội")) return Icons.medical_services_rounded;    if (name.contains("ngoại")) return Icons.biotech_rounded;    if (name.contains("da liễu")) return Icons.face_retouching_natural_rounded;    if (name.contains("tai") || name.contains("mũi") || name.contains("họng"))      return Icons.hearing_rounded;    if (name.contains("răng") || name.contains("hàm"))      return Icons.sentiment_satisfied_alt;    return Icons.label_important_outline;  }  // --- HÀM NHÓM LỊCH HẸN THEO THÁNG ---  Map<String, List<Map<String, dynamic>>> _groupAppointmentsByMonth() {    Map<String, List<Map<String, dynamic>>> groups = {};    List<Map<String, dynamic>> sortedList = List.from(bookedAppointments);    sortedList.sort(      (a, b) => (b['fullDateTime'] as DateTime).compareTo(        a['fullDateTime'] as DateTime,      ),    );    for (var app in sortedList) {      DateTime date = app['fullDateTime'] as DateTime;      String monthKey = isVietnamese          ? "Tháng ${DateFormat('MM, yyyy').format(date)}"          : DateFormat('MMMM yyyy').format(date);      if (groups[monthKey] == null) groups[monthKey] = [];      groups[monthKey]!.add(app);    }    return groups;  }  void _loadAppState() async {    final prefs = await SharedPreferences.getInstance();    setState(() {      isVietnamese = prefs.getBool('isVietnamese') ?? true;    });  }  void _fetchAppointments() async {    if (user == null) return;    try {      final snapshot = await FirebaseFirestore.instance          .collection('appointments')          .where('userId', isEqualTo: user?.uid)          .get();      final List<Map<String, dynamic>> loadedData = snapshot.docs.map((doc) {        final data = doc.data();        return {          'id': doc.id,          'name': data['doctorName'] ?? 'Bác sĩ',          'image': data['image'] ?? 'assets/images/logo.png',          'patient': data['patientName'] ?? 'Bệnh nhân',          'hospital': data['hospital'] ?? 'Bệnh viện chưa xác định',          'date': data['date'] ?? '',          'time': data['time'] ?? '',          'dept': data['dept'] ?? '',          'fullDateTime': data['fullDateTime'] != null              ? DateTime.parse(data['fullDateTime'])              : DateTime.now(),        };      }).toList();      setState(() {        bookedAppointments = loadedData;      });    } catch (e) {      debugPrint("Lỗi tải lịch hẹn: $e");    }  }  void _initNotifications() async {    const AndroidInitializationSettings initializationSettingsAndroid =        AndroidInitializationSettings('@mipmap/ic_launcher');    const InitializationSettings initializationSettings =        InitializationSettings(android: initializationSettingsAndroid);    await flutterLocalNotificationsPlugin.initialize(initializationSettings);    final platform = flutterLocalNotificationsPlugin        .resolvePlatformSpecificImplementation<          AndroidFlutterLocalNotificationsPlugin        >();    if (platform != null) {      await platform.requestNotificationsPermission();    }    tz.initializeTimeZones();  }  Future<void> _showNotification(    String patientName,    String doctorName,    String time,  ) async {    const AndroidNotificationDetails androidPlatformChannelSpecifics =        AndroidNotificationDetails(          'mediapp_booking_channel',          'Thông báo Mediapp',          importance: Importance.max,          priority: Priority.high,          showWhen: true,          icon: '@mipmap/ic_launcher',        );    const NotificationDetails platformChannelSpecifics = NotificationDetails(      android: androidPlatformChannelSpecifics,    );    await flutterLocalNotificationsPlugin.show(      DateTime.now().millisecond,      isVietnamese          ? 'Mediapp: Đặt lịch thành công! ✅'          : 'Mediapp: Booking Success! ✅',      isVietnamese          ? 'Bệnh nhân $patientName có lịch với $doctorName vào $time'          : 'Patient $patientName has a schedule with $doctorName at $time',      platformChannelSpecifics,    );  }  void _resetChat() {    setState(() {      _messages = [        {          "text": isVietnamese              ? "Chào bạn! Tôi là chatbot bác sĩ. Bạn cần hỗ trợ gì?"              : "Hello ! I am your AI Doctor. How can I help you?",          "isMe": false,        },      ];    });  }  void _handleSendMessage() {    String text = _chatController.text.trim();    if (text.isEmpty) return;    setState(() {      _messages.add({"text": text, "isMe": true});      _isTyping = true;    });    _chatController.clear();    Future.delayed(const Duration(milliseconds: 1500), () {      if (mounted) {        String resp = _getBotResponse(text);        setState(() {          _messages.add({"text": resp, "isMe": false});          _isTyping = false;        });      }    });  }  String _getBotResponse(String input) {    input = input.toLowerCase();    if (isVietnamese) {      if (input.contains("chào"))        return "Chào bạn! Chúc bạn ngày mới tốt lành.";      return "Bác sĩ đã nhận được thông tin từ bạn!";    } else {      return "Doctor has received your message!";    }  }  Future<void> _makePhoneCall(String phoneNumber) async {    final Uri launchUri = Uri(scheme: 'tel', path: phoneNumber);    if (await canLaunchUrl(launchUri)) {      await launchUrl(launchUri);    }  }  Future<void> _bookDoctor(Map<String, dynamic> doc) async {    final DateTime? d = await showDatePicker(      context: context,      initialDate: DateTime.now(),      firstDate: DateTime.now(),      lastDate: DateTime(2027),    );    if (d == null) return;    final TimeOfDay? t = await showTimePicker(      context: context,      initialTime: TimeOfDay.now(),    );    if (t == null) return;    _nameController.clear();    final String? pName = await showModalBottomSheet<String>(      context: context,      isScrollControlled: true,      backgroundColor: Colors.transparent,      builder: (ctx) => Container(        padding: EdgeInsets.only(          bottom: MediaQuery.of(ctx).viewInsets.bottom + 20,          left: 25,          right: 25,          top: 25,        ),        decoration: BoxDecoration(          color: Theme.of(context).scaffoldBackgroundColor,          borderRadius: const BorderRadius.vertical(top: Radius.circular(30)),        ),        child: Column(          mainAxisSize: MainAxisSize.min,          crossAxisAlignment: CrossAxisAlignment.start,          children: [            Center(              child: Container(                width: 50,                height: 5,                decoration: BoxDecoration(                  color: Colors.grey[300],                  borderRadius: BorderRadius.circular(10),                ),              ),            ),            const SizedBox(height: 20),            Row(              children: [                const Icon(                  Icons.person_add_alt_1,                  color: Colors.blue,                  size: 28,                ),                const SizedBox(width: 10),                Text(                  lang['patient'],                  style: const TextStyle(                    fontSize: 20,                    fontWeight: FontWeight.bold,                  ),                ),              ],            ),            const SizedBox(height: 10),            Text(              isVietnamese                  ? "Vui lòng nhập tên người sẽ đến khám bệnh"                  : "Please enter the name of the patient",              style: const TextStyle(color: Colors.grey, fontSize: 14),            ),            const SizedBox(height: 20),            TextField(              controller: _nameController,              autofocus: true,              decoration: InputDecoration(                hintText: isVietnamese                    ? "Ví dụ: Nguyễn Văn A..."                    : "Ex: John Doe...",                filled: true,                border: OutlineInputBorder(                  borderRadius: BorderRadius.circular(15),                  borderSide: BorderSide.none,                ),              ),            ),            const SizedBox(height: 25),            SizedBox(              width: double.infinity,              height: 55,              child: ElevatedButton(                onPressed: () => Navigator.pop(ctx, _nameController.text),                style: ElevatedButton.styleFrom(                  backgroundColor: Colors.blue,                  shape: RoundedRectangleBorder(                    borderRadius: BorderRadius.circular(15),                  ),                ),                child: Text(                  isVietnamese ? "XÁC NHẬN ĐẶT LỊCH" : "CONFIRM BOOKING",                  style: const TextStyle(                    color: Colors.white,                    fontWeight: FontWeight.bold,                  ),                ),              ),            ),          ],        ),      ),    );    if (pName == null || pName.isEmpty) return;    DateTime sel = DateTime(d.year, d.month, d.day, t.hour, t.minute);    bool conflict = bookedAppointments.any(      (app) =>          app['name'] == doc['name'] &&          (sel.difference(app['fullDateTime'] as DateTime).inMinutes.abs() <              30),    );    if (conflict) {      ScaffoldMessenger.of(context).showSnackBar(        SnackBar(          content: Text(            isVietnamese ? "Lịch này đã có người đặt!" : "Slot taken!",          ),          backgroundColor: Colors.orange,        ),      );    } else {      String timeStr = t.format(context);      try {        await FirebaseFirestore.instance.collection('appointments').add({          'userId': user?.uid,          'doctorName': doc['name'],          'patientName': pName,          'hospital': _selectedHospital,          'image': doc['image'],          'date': DateFormat('dd/MM/yyyy').format(d),          'time': timeStr,          'dept': doc['dept'],          'fullDateTime': sel.toIso8601String(),          'createdAt': FieldValue.serverTimestamp(),        });        _fetchAppointments();        await _showNotification(pName, doc['name']!, timeStr);        ScaffoldMessenger.of(context).showSnackBar(          SnackBar(            content: Text(              isVietnamese ? "Đặt lịch thành công!" : "Booking success!",            ),            backgroundColor: Colors.green,          ),        );      } catch (e) {        debugPrint("Lỗi đặt lịch: $e");      }    }  }  void _showError(String m) {    showDialog(      context: context,      builder: (c) => AlertDialog(        title: const Text("Mediapp"),        content: Text(m),        actions: [          TextButton(            onPressed: () => Navigator.pop(c),            child: const Text("OK"),          ),        ],      ),    );  }  // --- TAB CHAT ---  Widget _buildChatTab() {    return Column(      children: [        Align(          alignment: Alignment.centerRight,          child: TextButton.icon(            onPressed: _resetChat,            icon: const Icon(Icons.refresh, size: 18),            label: Text(lang['reset_chat']),          ),        ),        Expanded(          child: ListView.builder(            padding: const EdgeInsets.symmetric(horizontal: 20),            itemCount: _messages.length,            itemBuilder: (context, index) => _ChatBubble(              text: _messages[index]["text"],              isMe: _messages[index]["isMe"],            ),          ),        ),        if (_isTyping)          Padding(            padding: const EdgeInsets.only(left: 20, bottom: 10),            child: Align(              alignment: Alignment.centerLeft,              child: Text(                lang['bot_typing'],                style: const TextStyle(                  fontStyle: FontStyle.italic,                  color: Colors.grey,                  fontSize: 12,                ),              ),            ),          ),        _buildChatInputArea(),      ],    );  }  Widget _buildChatInputArea() {    return Container(      padding: const EdgeInsets.all(15),      color: Theme.of(context).scaffoldBackgroundColor,      child: Row(        children: [          Expanded(            child: TextField(              controller: _chatController,              decoration: InputDecoration(                hintText: lang['chat_hint'],                filled: true,                border: OutlineInputBorder(                  borderRadius: BorderRadius.circular(30),                  borderSide: BorderSide.none,                ),              ),            ),          ),          const SizedBox(width: 10),          CircleAvatar(            backgroundColor: Colors.blue,            child: IconButton(              icon: const Icon(Icons.send, color: Colors.white, size: 20),              onPressed: _handleSendMessage,            ),          ),        ],      ),    );  }  Widget _buildHomeTab() {    return SingleChildScrollView(      controller: _scrollController,      padding: const EdgeInsets.symmetric(horizontal: 20),      child: Column(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          const SizedBox(height: 10),          Text(lang['welcome'], style: const TextStyle(color: Colors.grey)),          if (_selectedHospital == null) ...[            Text(              lang['select_hosp'],              style: const TextStyle(fontSize: 26, fontWeight: FontWeight.bold),            ),            const SizedBox(height: 8),            Text(              lang['hosp_desc'],              style: const TextStyle(color: Colors.grey, fontSize: 14),            ),            const SizedBox(height: 25),            _buildHospitalGrid(),          ] else ...[            Row(              mainAxisAlignment: MainAxisAlignment.spaceBetween,              children: [                Expanded(                  child: Text(                    _selectedHospital!,                    style: const TextStyle(                      fontSize: 22,                      fontWeight: FontWeight.bold,                      color: Colors.blue,                    ),                  ),                ),                TextButton.icon(                  onPressed: () => setState(() {                    _selectedHospital = null;                    _selectedDeptFilter = null;                  }),                  icon: const Icon(Icons.swap_horiz, size: 18),                  label: Text(lang['back_hosp']),                ),              ],            ),            const SizedBox(height: 15),            _buildSearchBar(),            const SizedBox(height: 20),            Row(              mainAxisAlignment: MainAxisAlignment.spaceBetween,              children: [                Text(                  lang['dept'],                  style: const TextStyle(                    fontSize: 18,                    fontWeight: FontWeight.bold,                  ),                ),                if (_selectedDeptFilter != null)                  TextButton(                    onPressed: () => setState(() => _selectedDeptFilter = null),                    child: Text(                      lang['all'],                      style: const TextStyle(fontSize: 12),                    ),                  ),              ],            ),            const SizedBox(height: 10),            _buildCategorySection(),            const SizedBox(height: 20),            _buildDoctorGrid(),          ],          const SizedBox(height: 40),        ],      ),    );  }  Widget _buildHospitalGrid() {    return StreamBuilder<QuerySnapshot>(      stream: FirebaseFirestore.instance          .collection('hospitals')          .orderBy('createdAt', descending: false)          .snapshots(),      builder: (context, snapshot) {        if (snapshot.hasError)          return const Center(child: Text("Lỗi tải bệnh viện"));        if (!snapshot.hasData)          return const Center(child: CircularProgressIndicator());        final docs = snapshot.data!.docs;        return ListView.builder(          shrinkWrap: true,          physics: const NeverScrollableScrollPhysics(),          itemCount: docs.length,          itemBuilder: (context, i) {            String hospName = docs[i]['name'];            return Container(              margin: const EdgeInsets.only(bottom: 15),              child: InkWell(                onTap: () => setState(() => _selectedHospital = hospName),                borderRadius: BorderRadius.circular(20),                child: Container(                  padding: const EdgeInsets.all(20),                  decoration: BoxDecoration(                    gradient: LinearGradient(                      colors: [Colors.blue.shade400, Colors.blue.shade700],                      begin: Alignment.topLeft,                      end: Alignment.bottomRight,                    ),                    borderRadius: BorderRadius.circular(20),                    boxShadow: [                      BoxShadow(                        color: Colors.blue.withOpacity(0.3),                        blurRadius: 10,                        offset: const Offset(0, 5),                      ),                    ],                  ),                  child: Row(                    children: [                      Container(                        padding: const EdgeInsets.all(12),                        decoration: const BoxDecoration(                          color: Colors.white24,                          shape: BoxShape.circle,                        ),                        child: const Icon(                          Icons.local_hospital_rounded,                          color: Colors.white,                          size: 30,                        ),                      ),                      const SizedBox(width: 20),                      Expanded(                        child: Column(                          crossAxisAlignment: CrossAxisAlignment.start,                          children: [                            Text(                              hospName,                              style: const TextStyle(                                color: Colors.white,                                fontWeight: FontWeight.bold,                                fontSize: 18,                              ),                            ),                            const SizedBox(height: 4),                            Text(                              isVietnamese                                  ? "Xem danh sách bác sĩ"                                  : "See doctors list",                              style: TextStyle(                                color: Colors.white.withOpacity(0.8),                                fontSize: 13,                              ),                            ),                          ],                        ),                      ),                      const Icon(                        Icons.arrow_forward_ios_rounded,                        color: Colors.white,                        size: 18,                      ),                    ],                  ),                ),              ),            );          },        );      },    );  }  Widget _buildSearchBar() => TextField(    decoration: InputDecoration(      hintText: lang['search_hint'],      prefixIcon: const Icon(Icons.search),      filled: true,      border: OutlineInputBorder(        borderRadius: BorderRadius.circular(15),        borderSide: BorderSide.none,      ),    ),  );  Widget _buildCategorySection() {    return StreamBuilder<QuerySnapshot>(      stream: FirebaseFirestore.instance          .collection('specialities')          .orderBy('createdAt', descending: false)          .snapshots(),      builder: (context, snapshot) {        if (!snapshot.hasData) return const SizedBox();        final specs = snapshot.data!.docs;        return SizedBox(          height: 100,          child: ListView.builder(            scrollDirection: Axis.horizontal,            itemCount: specs.length,            itemBuilder: (context, i) {              String name = specs[i]['name'];              return _catItem(_getIconForSpeciality(name), name, name);            },          ),        );      },    );  }  Widget _catItem(IconData icon, String label, String deptKey) =>      GestureDetector(        onTap: () => setState(() => _selectedDeptFilter = deptKey),        child: Padding(          padding: const EdgeInsets.only(right: 20),          child: Column(            children: [              CircleAvatar(                radius: 28,                backgroundColor: _selectedDeptFilter == deptKey                    ? Colors.blue                    : Colors.blue.withOpacity(0.1),                child: Icon(                  icon,                  color: _selectedDeptFilter == deptKey                      ? Colors.white                      : Colors.blue,                  size: 28,                ),              ),              const SizedBox(height: 8),              Text(                label,                style: TextStyle(                  fontSize: 11,                  fontWeight: _selectedDeptFilter == deptKey                      ? FontWeight.bold                      : FontWeight.w500,                  color: _selectedDeptFilter == deptKey ? Colors.blue : null,                ),              ),            ],          ),        ),      );  // --- HÀM LỌC BÁC SĨ (KẾT HỢP DÙNG CHUNG VÀ RIÊNG) ---  Widget _buildDoctorGrid() {    return StreamBuilder<QuerySnapshot>(      stream: FirebaseFirestore.instance          .collection('doctors')          .orderBy('createdAt', descending: true)          .snapshots(),      builder: (context, snapshot) {        if (snapshot.hasError)          return const Center(            child: Padding(              padding: EdgeInsets.all(20),              child: Text(                "Đang kết nối hệ thống lọc...",                textAlign: TextAlign.center,              ),            ),          );        if (snapshot.connectionState == ConnectionState.waiting)          return const Center(child: CircularProgressIndicator());        final List<DocumentSnapshot> allDocs = snapshot.data!.docs;        // Bổ sung Stream lấy danh sách bệnh viện để xác định "bác sĩ mới" hay "bác sĩ cũ"        return StreamBuilder<QuerySnapshot>(          stream: FirebaseFirestore.instance              .collection('hospitals')              .snapshots(),          builder: (ctx, hospSnapshot) {            if (!hospSnapshot.hasData) return const SizedBox();            // Danh sách tên các bệnh viện đã đăng ký            List<String> registeredHospitals = hospSnapshot.data!.docs                .map(                  (d) => (d.data() as Map<String, dynamic>)['name'].toString(),                )                .toList();            final filteredDocs = allDocs.where((doc) {              final data = doc.data() as Map<String, dynamic>;              final String doctorHosp = data['hospital'] ?? '';              final String doctorDept = data['dept'] ?? '';              // LOGIC: Bác sĩ cũ (không thuộc danh sách đăng ký mới) HOẶC khớp bệnh viện đang chọn              bool isOldDoctor = !registeredHospitals.contains(doctorHosp);              bool isMatchingNewDoctor = (doctorHosp == _selectedHospital);              // Lọc Chuyên khoa              bool matchesDept =                  (_selectedDeptFilter == null) ||                  (doctorDept == _selectedDeptFilter);              return (isOldDoctor || isMatchingNewDoctor) && matchesDept;            }).toList();            if (filteredDocs.isEmpty)              return const Center(                child: Padding(                  padding: EdgeInsets.all(20),                  child: Text("Không có bác sĩ nào phù hợp."),                ),              );            return GridView.builder(              shrinkWrap: true,              physics: const NeverScrollableScrollPhysics(),              gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(                crossAxisCount: 2,                mainAxisSpacing: 15,                crossAxisSpacing: 15,                childAspectRatio: 0.8,              ),              itemCount: filteredDocs.length,              itemBuilder: (ctx, i) {                final data = filteredDocs[i].data() as Map<String, dynamic>;                final doc = {                  'id': filteredDocs[i].id,                  'name': data['name'] ?? '',                  'dept': data['dept'] ?? '',                  'hospital': data['hospital'] ?? '',                  'image': data['image'] ?? '',                };                bool isAsset = !doc['image']!.startsWith('http');                return GestureDetector(                  onTap: () => _bookDoctor(doc),                  child: Container(                    decoration: BoxDecoration(                      color: Theme.of(context).cardTheme.color ?? Colors.white,                      borderRadius: BorderRadius.circular(15),                      border: Border.all(color: Colors.grey.withOpacity(0.1)),                    ),                    child: Column(                      children: [                        Expanded(                          child: ClipRRect(                            borderRadius: const BorderRadius.vertical(                              top: Radius.circular(15),                            ),                            child: isAsset                                ? Image.asset(                                    doc['image']!,                                    fit: BoxFit.cover,                                    width: double.infinity,                                    errorBuilder: (c, e, s) =>                                        const Icon(Icons.person, size: 50),                                  )                                : Image.network(                                    doc['image']!,                                    fit: BoxFit.cover,                                    width: double.infinity,                                    errorBuilder: (c, e, s) =>                                        const Icon(Icons.person, size: 50),                                  ),                          ),                        ),                        Padding(                          padding: const EdgeInsets.all(8),                          child: Column(                            children: [                              Text(                                doc['name']!,                                style: const TextStyle(                                  fontWeight: FontWeight.bold,                                  fontSize: 12,                                ),                                textAlign: TextAlign.center,                              ),                              Text(                                doc['dept']!,                                style: const TextStyle(                                  color: Colors.grey,                                  fontSize: 10,                                  fontStyle: FontStyle.italic,                                ),                              ),                              const SizedBox(height: 4),                              Text(                                lang['book_btn'],                                style: const TextStyle(                                  color: Colors.blue,                                  fontSize: 10,                                  fontWeight: FontWeight.bold,                                ),                              ),                            ],                          ),                        ),                      ],                    ),                  ),                );              },            );          },        );      },    );  }  Widget _buildHistoryTab() {    final groupedData = _groupAppointmentsByMonth();    return Padding(      padding: const EdgeInsets.all(20),      child: Column(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          Text(            lang['my_booking'],            style: const TextStyle(              fontSize: 22,              fontWeight: FontWeight.bold,              color: Colors.blue,            ),          ),          const SizedBox(height: 15),          Expanded(            child: bookedAppointments.isEmpty                ? Center(child: Text(lang['no_booking']))                : ListView.builder(                    itemCount: groupedData.length,                    itemBuilder: (context, index) {                      String month = groupedData.keys.elementAt(index);                      List<Map<String, dynamic>> apps = groupedData[month]!;                      return Column(                        crossAxisAlignment: CrossAxisAlignment.start,                        children: [                          Padding(                            padding: const EdgeInsets.symmetric(vertical: 10),                            child: Row(                              children: [                                Container(                                  padding: const EdgeInsets.symmetric(                                    horizontal: 12,                                    vertical: 6,                                  ),                                  decoration: BoxDecoration(                                    color: Colors.blue.withOpacity(0.1),                                    borderRadius: BorderRadius.circular(20),                                  ),                                  child: Text(                                    month,                                    style: const TextStyle(                                      fontWeight: FontWeight.bold,                                      color: Colors.blue,                                      fontSize: 14,                                    ),                                  ),                                ),                                const Expanded(child: Divider(indent: 10)),                              ],                            ),                          ),                          ...apps.map((app) {                            bool isAsset = !app['image'].startsWith('http');                            return Card(                              margin: const EdgeInsets.only(bottom: 10),                              elevation: 2,                              shape: RoundedRectangleBorder(                                borderRadius: BorderRadius.circular(15),                              ),                              child: ListTile(                                leading: CircleAvatar(                                  backgroundImage: isAsset                                      ? AssetImage(app['image'])                                            as ImageProvider                                      : NetworkImage(app['image']),                                ),                                title: Text(                                  app['name'],                                  style: const TextStyle(                                    fontWeight: FontWeight.bold,                                  ),                                ),                                subtitle: Text(                                  "${lang['patient']}: ${app['patient']}\n🏢 ${app['hospital']}\n📅 ${app['date']} - ${app['time']}",                                  style: const TextStyle(fontSize: 12),                                ),                                isThreeLine: true,                                trailing: IconButton(                                  icon: const Icon(                                    Icons.delete_outline,                                    color: Colors.redAccent,                                  ),                                  onPressed: () async {                                    await FirebaseFirestore.instance                                        .collection('appointments')                                        .doc(app['id'])                                        .delete();                                    _fetchAppointments();                                  },                                ),                              ),                            );                          }).toList(),                        ],                      );                    },                  ),          ),        ],      ),    );  }  Widget _buildProfileTab() {    final themeProvider = Provider.of<ThemeProvider>(context);    return SingleChildScrollView(      padding: const EdgeInsets.all(20),      child: Column(        children: [          const SizedBox(height: 20),          Stack(            alignment: Alignment.bottomRight,            children: [              CircleAvatar(                radius: 60,                backgroundColor: _avatarColor,                child: const Icon(Icons.person, size: 60, color: Colors.white),              ),              CircleAvatar(                backgroundColor: Colors.white,                radius: 18,                child: IconButton(                  icon: const Icon(                    Icons.camera_alt,                    size: 18,                    color: Colors.blue,                  ),                  onPressed: () => setState(                    () => _avatarColor = (List.of(                      Colors.primaries,                    )..shuffle()).first,                  ),                ),              ),            ],          ),          const SizedBox(height: 20),          Text(            user?.email ?? "User",            style: const TextStyle(fontSize: 18, fontWeight: FontWeight.bold),          ),          const SizedBox(height: 30),          ListTile(            leading: Icon(              themeProvider.isDarkMode ? Icons.dark_mode : Icons.light_mode,              color: Colors.amber,            ),            title: Text(isVietnamese ? "Chế độ tối" : "Dark Mode"),            trailing: Switch(              value: themeProvider.isDarkMode,              onChanged: (v) => themeProvider.toggleTheme(),            ),          ),          if (user?.email == "quocthang15082004@gmail.com")            _profileMenu(Icons.admin_panel_settings, "Trang Quản Trị", () {              Navigator.push(                context,                MaterialPageRoute(builder: (c) => const AdminPage()),              );            }),          _profileMenu(Icons.lock_outline, lang['change_pw'], () {            /* Logic đổi MK */          }),          _profileMenu(Icons.logout, lang['logout'], () async {            await FirebaseAuth.instance.signOut();            Navigator.pushReplacement(              context,              MaterialPageRoute(builder: (c) => Login()),            );          }, isRed: true),        ],      ),    );  }  Widget _getBody() {    switch (_currentIndex) {      case 0:        return _buildHomeTab();      case 1:        return _buildHistoryTab();      case 2:        return _buildChatTab();      case 3:        return _buildProfileTab();      default:        return _buildHomeTab();    }  }  Widget _profileMenu(    IconData icon,    String title,    VoidCallback onTap, {    bool isRed = false,  }) => ListTile(    leading: Icon(icon, color: isRed ? Colors.red : Colors.blue),    title: Text(      title,      style: TextStyle(        color: isRed            ? Colors.red            : (Theme.of(context).brightness == Brightness.dark                  ? Colors.white                  : Colors.black),      ),    ),    trailing: const Icon(Icons.arrow_forward_ios, size: 16),    onTap: onTap,  );  @override  Widget build(BuildContext context) {    return Scaffold(      appBar: AppBar(        title: const Text(          "Mediapp",          style: TextStyle(color: Colors.blue, fontWeight: FontWeight.bold),        ),        backgroundColor: Theme.of(context).appBarTheme.backgroundColor,        elevation: 0,        actions: [          IconButton(            icon: const Icon(Icons.phone, color: Colors.red),            onPressed: () => _makePhoneCall("19001234"),          ),          TextButton(            onPressed: () async {              setState(() => isVietnamese = !isVietnamese);              final prefs = await SharedPreferences.getInstance();              await prefs.setBool('isVietnamese', isVietnamese);              _resetChat();            },            child: Text(              isVietnamese ? "EN" : "VN",              style: const TextStyle(                color: Colors.blue,                fontWeight: FontWeight.bold,              ),            ),          ),        ],      ),      body: _getBody(),      bottomNavigationBar: BottomNavigationBar(        currentIndex: _currentIndex,        onTap: (v) => setState(() => _currentIndex = v),        selectedItemColor: Colors.blue,        unselectedItemColor: Colors.grey,        type: BottomNavigationBarType.fixed,        items: [          BottomNavigationBarItem(            icon: const Icon(Icons.home),            label: lang['home'],          ),          BottomNavigationBarItem(            icon: const Icon(Icons.calendar_today),            label: lang['booking'],          ),          BottomNavigationBarItem(            icon: const Icon(Icons.message),            label: lang['chat'],          ),          BottomNavigationBarItem(            icon: const Icon(Icons.person),            label: lang['profile'],          ),        ],      ),    );  }}class _ChatBubble extends StatelessWidget {  final String text;  final bool isMe;  const _ChatBubble({required this.text, required this.isMe});  @override  Widget build(BuildContext context) {    return Align(      alignment: isMe ? Alignment.centerRight : Alignment.centerLeft,      child: Container(        margin: const EdgeInsets.symmetric(vertical: 5),        padding: const EdgeInsets.all(12),        decoration: BoxDecoration(          color: isMe              ? Colors.blue              : (Theme.of(context).brightness == Brightness.dark                    ? Colors.grey[800]                    : Colors.grey.shade200),          borderRadius: BorderRadius.circular(15),        ),        child: Text(          text,          style: TextStyle(            color: isMe                ? Colors.white                : (Theme.of(context).brightness == Brightness.dark                      ? Colors.white                      : Colors.black),          ),        ),      ),    );  }}